sys_ui_action.script:
action.setRedirectURL(current);

var runSysId = current.getUniqueValue();

var moduleMap = {
    "ITSM":          "itsm_score",
    "ITOM":          "itom_score",
    "CMDB":          "cmdb_score",
    "HRSD":          "hrsd_score",
    "CSM":           "csm_score",
    "FIELD_SERVICE": "field_service_score",
    "AIOPS":         "aiops_score",
    "GRC":           "grc_score",
    "SPM":           "spm_score",
    "PLATFORM":      "platform_score",
    "VIRTUAL_AGENT": "va_score",
    "DEX":           "dex_score",
    "SECOPS":        "secops_score",
    "HS":            "hs_score",
    "OTSM":          "otsm_score",
    "CREATOR":       "creator_score",
    "SPO":           "spo_score",
    "TPRM":          "tprm_score",
    "LSD":           "lsd_score",
    "WSD":           "wsd_score",
    "HAM":           "ham_score",
    "SAM":           "sam_score"
};

var EXCLUDED = { "not_applicable": true, "manual": true };

var totalPoints = 0;
var totalDenominator = 0;
var modulesScored = 0;

for (var module in moduleMap) {
    var scoreField = moduleMap[module];
    var points = 0;
    var denominator = 0;

    var ga = new GlideAggregate("x_snc_airop_check_result");
    ga.addQuery("assessment_run", runSysId);
    ga.addQuery("module", module);
    ga.addAggregate("COUNT");
    ga.groupBy("status");
    ga.query();

    while (ga.next()) {
        var status = ga.getValue("status");
        var count = parseInt(ga.getAggregate("COUNT"));
        if (EXCLUDED[status]) continue;
        denominator += count;
        if (status === "ready")           points += count * 1.0;
        if (status === "needs_attention") points += count * 0.5;
    }

    var score = denominator > 0 ? Math.round((points / denominator) * 100) : 0;
    current.setValue(scoreField, score);

    if (denominator > 0) {
        totalPoints += points;
        totalDenominator += denominator;
        modulesScored++;
    }

    gs.addInfoMessage(module + ": " + points + "/" + denominator + " = " + score + "%");
}

var overallScore = totalDenominator > 0 ? Math.round((totalPoints / totalDenominator) * 100) : 0;
current.setValue("overall_score", overallScore);
current.setValue("score_calculation_status", "updated");
current.assessment_log = 'Scores manually recalculated by ' + gs.getUserDisplayName() + '. Overall: ' + overallScore + '% across ' + modulesScored + ' modules.';
current.update();
gs.addInfoMessage("Overall Readiness: " + overallScore + "% across " + modulesScored + " modules.");
